switch (msg.payload.type) {
    case 'evt_precip':
        msg.target = 'Precipitation Start';
        break;
    case 'evt_strike':
        msg.target = 'Lightning Strike';
        break;
    case 'obs_st':
        msg.target = 'Observation';
        break;
    case 'rapid_wind':
        msg.target = 'Rapid Wind';
        break;
    default:
        return null;
}

return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const obs = msg.payload.obs[0];

const precipTypes = { 0: 'None', 1: 'Rain', 2: 'Hail', 3: 'Rain+Hail' };

// Unit conversions
const msToMph  = v => Math.round(v * 2.23694 * 10) / 10;
const cToF     = v => Math.round((v * 9/5 + 32) * 10) / 10;
const mbToInHg = v => Math.round(v * 0.02953 * 100) / 100;
const mmToIn   = v => Math.round(v * 0.0393701 * 1000) / 1000;
const kmToMi   = v => Math.round(v * 0.621371 * 10) / 10;

const notification = {
    topic: 'highland/event/weather/station/observation',
    payload: JSON.stringify({
        timestamp: new Date(obs[0] * 1000).toISOString(),
        serial_number: msg.payload.serial_number,
        source: 'tempest'
    }),
    retain: false
}

const state = {
    topic: 'highland/state/weather/station',
    payload: JSON.stringify({
        timestamp:          new Date(obs[0] * 1000).toISOString(),
        wind_lull:          msToMph(obs[1]),
        wind_avg:           msToMph(obs[2]),
        wind_gust:          msToMph(obs[3]),
        wind_direction:     obs[4],
        pressure:           mbToInHg(obs[6]),
        temperature:        cToF(obs[7]),
        humidity:           obs[8],
        uv_index:           obs[10],
        solar_radiation:    obs[11],
        rain_accumulated:   mmToIn(obs[12]),
        precipitation_type: precipTypes[obs[13]] ?? 'None',
        lightning_distance: obs[14] > 0 ? kmToMi(obs[14]) : null,
        lightning_count:    obs[15],
        battery:            obs[16],
        report_interval:    obs[17],
        source:             'tempest',
        serial_number:      msg.payload.serial_number
    }),
    retain: true
}

node.status({ fill: 'green', shape: 'dot',
    text: formatStatus(`${cToF(obs[7])}°F`)
});

node.send([state, null]);
node.send([notification, null]);

return [null, msg];

const device = {
    identifiers: ["highland_weather_station"],
    name: "Highland Weather Station",
    model: "Tempest",
    manufacturer: "WeatherFlow"
};

const state_topic = "highland/state/weather/station";
const base = "homeassistant/sensor/highland_weather_station";

const sensors = [
    {
        id: "temperature",
        name: "Temperature",
        device_class: "temperature",
        unit: "°F",
        state_class: "measurement"
    },
    {
        id: "humidity",
        name: "Humidity",
        device_class: "humidity",
        unit: "%",
        state_class: "measurement"
    },
    {
        id: "pressure",
        name: "Pressure",
        device_class: "atmospheric_pressure",
        unit: "inHg",
        state_class: "measurement"
    },
    {
        id: "wind_avg",
        name: "Wind Speed",
        unit: "mph",
        state_class: "measurement"
    },
    {
        id: "wind_gust",
        name: "Wind Gust",
        unit: "mph",
        state_class: "measurement"
    },
    {
        id: "wind_lull",
        name: "Wind Lull",
        unit: "mph",
        state_class: "measurement"
    },
    {
        id: "wind_direction",
        name: "Wind Direction",
        unit: "°",
        state_class: "measurement"
    },
    {
        id: "uv_index",
        name: "UV Index",
        state_class: "measurement"
    },
    {
        id: "solar_radiation",
        name: "Solar Radiation",
        device_class: "irradiance",
        unit: "W/m²",
        state_class: "measurement"
    },
    {
        id: "rain_accumulated",
        name: "Rain Accumulated",
        device_class: "precipitation",
        unit: "in",
        state_class: "total_increasing"
    },
    {
        id: "precipitation_type",
        name: "Precipitation Type"
    },
    {
        id: "lightning_distance",
        name: "Lightning Distance",
        device_class: "distance",
        unit: "mi"
    },
    {
        id: "lightning_count",
        name: "Lightning Count",
        state_class: "total_increasing"
    },
    {
        id: "battery",
        name: "Battery",
        device_class: "voltage",
        unit: "V",
        state_class: "measurement",
        entity_category: "diagnostic"
    }
];

for (const s of sensors) {
    const config = {
        name: s.name,
        unique_id: `highland_station_${s.id}`,
        state_topic,
        value_template: `{{ value_json.${s.id} }}`,
        device
    };

    if (s.device_class)    config.device_class = s.device_class;
    if (s.unit)            config.unit_of_measurement = s.unit;
    if (s.state_class)     config.state_class = s.state_class;
    if (s.entity_category) config.entity_category = s.entity_category;

    node.send({
        topic: `${base}/${s.id}/config`,
        payload: JSON.stringify(config),
        retain: true
    });
}

return null;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const evt = msg.payload.evt;

node.send([{
    topic: 'highland/event/weather/station/precipitation_start',
    payload: JSON.stringify({
        timestamp: new Date(evt[0] * 1000).toISOString(),
        serial_number: msg.payload.serial_number,
        source: 'tempest'
    }),
    retain: false
}, null]);

node.status({ fill: 'blue', shape: 'dot', text: formatStatus('STARTED') });

return [null, msg];

const evt = msg.payload.evt;
const kmToMi = v => Math.round(v * 0.621371 * 10) / 10;

node.send([{
    topic: 'highland/event/weather/station/lightning',
    payload: JSON.stringify({
        timestamp: new Date(evt[0] * 1000).toISOString(),
        distance_miles: kmToMi(evt[1]),
        energy: evt[2],
        serial_number: msg.payload.serial_number,
        source: 'tempest'
    }),
    retain: false
}, null]);

node.status({ fill: 'yellow', shape: 'dot', 
    text: `Strike ${kmToMi(evt[1])}mi` 
});

return [null,msg];
